import math

class QuantumFinanceSimulator:
    def amplitude_estimation_theoretical(self, P: float, M: int) -> float:
        """
        Teorik Quantum Amplitude Estimation hatası.
        P: Hedef olasılık
        M: Quantum Oracle çağrı sayısı
        """
        if M <= 0: return 1.0
        # O(1/M) convergence (Classical is O(1/sqrt(M)))
        return math.pi / M

